package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build platform-specific ping command
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.) use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outputStr)
	}

	// Parse the output to extract average latency
	avg, err := parseAverageLatency(outputStr)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avg, nil
}

// parseAverageLatency extracts the average latency from ping output
func parseAverageLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Try different patterns for different operating systems

	// Pattern 1: Linux/macOS format
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			re := regexp.MustCompile(`min/avg/max(?:/mdev|/stddev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				return strconv.ParseFloat(matches[1], 64)
			}
		}
	}

	// Pattern 2: Windows format
	// Average = 23ms
	for _, line := range lines {
		if strings.Contains(line, "Average") {
			re := regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				return strconv.ParseFloat(matches[1], 64)
			}
		}
	}

	// Pattern 3: Alternative format - extract from individual ping lines and calculate average
	var latencies []float64
	re := regexp.MustCompile(`time[=<]([\d.]+)\s*ms`)
	for _, line := range lines {
		matches := re.FindStringSubmatch(line)
		if len(matches) >= 2 {
			if latency, err := strconv.ParseFloat(matches[1], 64); err == nil {
				latencies = append(latencies, latency)
			}
		}
	}

	if len(latencies) > 0 {
		sum := 0.0
		for _, lat := range latencies {
			sum += lat
		}
		return sum / float64(len(latencies)), nil
	}

	return 0, errors.New("could not find latency statistics in ping output")
}

