package main

import (
	"errors"
	"fmt"
	"net"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Validate host to prevent command injection
	if !isValidHost(host) {
		return 0, errors.New("invalid host format")
	}

	// Build command arguments based on OS
	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", countStr, host)
	} else {
		// Unix-like systems use -c for count
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing RTT statistics
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round trip times") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		// Try Windows format: Minimum = 12ms, Maximum = 34ms, Average = 23ms
		reWindows := regexp.MustCompile(`Average = ([\d.]+)ms`)
		matches = reWindows.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// isValidHost validates that the host is either a valid IP address or hostname
func isValidHost(host string) bool {
	// Check if it's a valid IP address
	if net.ParseIP(host) != nil {
		return true
	}

	// Check if it's a valid hostname (RFC 1123)
	// Hostname can contain letters, digits, hyphens, and dots
	// Must not start or end with hyphen, max 253 chars total
	if len(host) > 253 {
		return false
	}

	// Simple regex for valid hostname
	hostnameRegex := regexp.MustCompile(`^[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$`)
	return hostnameRegex.MatchString(host)
}

