	"strconv"
	"strings"
)

// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	var avgPattern *regexp.Regexp

	// Determine OS and construct appropriate ping command
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
		// Windows output pattern: Average = <time>ms or Mittelwert = <time>ms (German)
		avgPattern = regexp.MustCompile(`(?:Average|Mittelwert)\s*=\s*(\d+(?:\.\d+)?)ms`)
	case "darwin", "linux":
		// Unix-like: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Unix output pattern: min/avg/max/stddev = <min>/<avg>/<max>/<stddev> ms
		// or: rtt min/avg/max/mdev = <min>/<avg>/<max>/<mdev> ms
		avgPattern = regexp.MustCompile(`(?:min/avg/max/(?:stddev|mdev)|rtt min/avg/max/mdev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Parse the output to extract average latency
	matches := avgPattern.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from output: %s", outputStr)
	}

	// Convert the extracted average to float64
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %w", err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	hosts := []string{"8.8.8.8", "1.1.1.1", "google.com"}
	count := 4

