package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build command arguments safely to prevent command injection
	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	// Different ping command syntax for different operating systems
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", countStr, host)
	default:
		// Linux, macOS, and other Unix-like systems use -c for count
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Parse the output to extract average latency
	outputStr := string(output)

	// Try to parse based on OS
	switch runtime.GOOS {
	case "windows":
		return parseWindowsPing(outputStr)
	default:
		return parseUnixPing(outputStr)
	}
}

// parseUnixPing parses ping output from Unix-like systems (Linux, macOS, etc.)
func parseUnixPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string

	// Look for the line containing RTT statistics
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Handles both formats:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	// Also handles cases without mdev/stddev
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max(?:/(?:mdev|stddev))? = [\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)? ms`)
	matches := re.FindStringSubmatch(statsLine)

	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// parseWindowsPing parses ping output from Windows systems
func parseWindowsPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Windows ping output format:
	// Minimum = 12ms, Maximum = 34ms, Average = 23ms
	for _, line := range lines {
		if strings.Contains(line, "Average") && strings.Contains(line, "ms") {
			re := regexp.MustCompile(`Average = (\d+)ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				avg, err := strconv.ParseFloat(matches[1], 64)
				if err != nil {
					return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
				}
				return avg, nil
			}
		}
	}

	return 0, errors.New("could not find average latency in ping output")
}

