package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build platform-specific ping command
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// Even if there's an error, try to parse the output as some packets may have succeeded
	if err != nil && outputStr == "" {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	// Parse the output based on platform
	avg, parseErr := parseLatency(outputStr)
	if parseErr != nil {
		if err != nil {
			return 0, fmt.Errorf("ping failed: %w (parse error: %v, output: %s)", err, parseErr, outputStr)
		}
		return 0, parseErr
	}

	return avg, nil
}

// parseLatency extracts the average latency from ping output
func parseLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Try different patterns for different platforms and locales
	patterns := []struct {
		linePattern string
		regex       *regexp.Regexp
	}{
		{
			// Linux/macOS: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
			linePattern: "rtt min/avg/max",
			regex:       regexp.MustCompile(`rtt min/avg/max(?:/mdev|/stddev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`),
		},
		{
			// macOS alternative: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
			linePattern: "round-trip",
			regex:       regexp.MustCompile(`round-trip min/avg/max(?:/stddev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`),
		},
		{
			// Windows: Average = 23ms
			linePattern: "Average",
			regex:       regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`),
		},
		{
			// Windows alternative: Minimum = 12ms, Maximum = 34ms, Average = 23ms
			linePattern: "Minimum",
			regex:       regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`),
		},
	}

	for _, pattern := range patterns {
		for _, line := range lines {
			if strings.Contains(line, pattern.linePattern) {
				matches := pattern.regex.FindStringSubmatch(line)
				if len(matches) >= 2 {
					avgStr := matches[1]
					avg, err := strconv.ParseFloat(avgStr, 64)
					if err != nil {
						return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
					}
					return avg, nil
				}
			}
		}
	}

	return 0, errors.New("could not find RTT statistics in ping output")
}

