		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
		// Windows output format: "Average = XXXms" or "Average = XXX ms"
		avgRegex = regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)ms`)
	case "darwin", "linux":
		// Unix-like: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Unix output format: "round-trip min/avg/max/stddev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
