		avgRegex = regexp.MustCompile(`(?:round-trip|rtt)\s+min/avg/max/(?:stddev|mdev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	// Parse the output to extract average latency
	outputStr := string(output)
	matches := avgRegex.FindStringSubmatch(outputStr)

	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", outputStr)
	}

	// Convert the extracted average latency to float64
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency to float: %v", err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	fmt.Printf("Measuring latency to %s with %d pings...\n", host, count)

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
