package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build platform-specific ping command
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.) use -c for count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outputStr)
	}

	// Parse the output based on the operating system
	if runtime.GOOS == "windows" {
		return parseWindowsPing(outputStr)
	}
	return parseUnixPing(outputStr)
}

// parseUnixPing parses ping output from Unix-like systems (Linux, macOS)
func parseUnixPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string

	// Look for the line containing RTT statistics
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using regex
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// or: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max(?:/mdev|/stddev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := re.FindStringSubmatch(statsLine)

	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// parseWindowsPing parses ping output from Windows systems
func parseWindowsPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string

	// Look for the line containing average time
	// Example: "Average = 23ms"
	for _, line := range lines {
		if strings.Contains(line, "Average") && strings.Contains(line, "ms") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find average statistics in ping output")
	}

	// Extract average latency
	re := regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
	matches := re.FindStringSubmatch(statsLine)

	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

