	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// isValidHost validates that the host string contains only safe characters
// Allows: alphanumeric, dots, hyphens, colons (IPv6), square brackets (IPv6), underscores
func isValidHost(host string) bool {
	// Allow valid hostname/IP characters
	// This regex allows:
