// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	var avgRegex *regexp.Regexp

	// Platform-specific ping command configuration
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
		// Windows output format: "Average = XXXms" or "Average = XXXms"
		avgRegex = regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)ms`)
	case "darwin", "linux":
		// Unix-like: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Unix output format: "min/avg/max/stddev = XXX/YYY/ZZZ/AAA ms"
		avgRegex = regexp.MustCompile(`min/avg/max(?:/[a-z]+)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Extract average latency from output
	matches := avgRegex.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse ping output: %s", outputStr)
	}

	// Parse the average latency value
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %v", err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	examples := []struct {
		host  string
		count int
	}{
		{"8.8.8.8", 4},
		{"localhost", 3},
		{"google.com", 5},
	}

	fmt.Println("Network Latency Measurement Tool")
	fmt.Println(strings.Repeat("=", 50))

	for _, example := range examples {
		fmt.Printf("\nPinging %s with %d attempts...\n", example.host, example.count)

		avgLatency, err := MeasureLatency(example.host, example.count)
		if err != nil {
			fmt.Printf("Error: %v\n", err)
			continue
		}

		fmt.Printf("Average latency: %.2f ms\n", avgLatency)
	}

	// Interactive example
	fmt.Println("\n" + strings.Repeat("=", 50))
	fmt.Println("Custom measurement:")

	customHost := "1.1.1.1"
	customCount := 4

	fmt.Printf("Measuring latency to %s (%d pings)...\n", customHost, customCount)
	avgLatency, err := MeasureLatency(customHost, customCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Result: %.2f ms\n", avgLatency)
	}
}

