package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build platform-specific ping command
	var cmd *exec.Cmd
	countStr := strconv.Itoa(count)

	switch runtime.GOOS {
	case "windows":
		// Windows uses -n for count
		cmd = exec.Command("ping", "-n", countStr, host)
	case "darwin", "linux", "freebsd", "openbsd", "netbsd":
		// Unix-like systems use -c for count
		cmd = exec.Command("ping", "-c", countStr, host)
	default:
		// Default to Unix-like behavior
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Parse the output to extract average latency
	outputStr := string(output)
	avg, err := parseAverageLatency(outputStr)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avg, nil
}

// parseAverageLatency extracts the average latency from ping output
// Supports multiple formats across different operating systems
func parseAverageLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Try Unix/Linux/macOS format first
	// Example: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// Example: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	for _, line := range lines {
		if strings.Contains(line, "rtt") || strings.Contains(line, "round-trip") {
			// More flexible regex to handle variations
			re := regexp.MustCompile(`(?:rtt|round-trip)\s+min/avg/max(?:/mdev|/stddev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				avg, err := strconv.ParseFloat(matches[1], 64)
				if err != nil {
					return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
				}
				return avg, nil
			}
		}
	}

	// Try Windows format
	// Example: Average = 23ms
	for _, line := range lines {
		if strings.Contains(line, "Average") || strings.Contains(line, "average") {
			re := regexp.MustCompile(`[Aa]verage\s*=\s*([\d.]+)\s*ms`)
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				avg, err := strconv.ParseFloat(matches[1], 64)
				if err != nil {
					return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
				}
				return avg, nil
			}
		}
	}

	// Fallback: calculate average from individual ping times
	avg, err := calculateAverageFromPingTimes(output)
	if err == nil {
		return avg, nil
	}

	return 0, errors.New("could not find or parse average latency in ping output")
}

// calculateAverageFromPingTimes calculates average from individual ping times as a fallback
func calculateAverageFromPingTimes(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var times []float64

	// Match patterns like "time=23.4 ms" or "time=23.4ms" or "time<1ms"
	re := regexp.MustCompile(`time[=<]([\d.]+)\s*ms`)

	for _, line := range lines {
		matches := re.FindStringSubmatch(line)
		if len(matches) >= 2 {
			time, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				times = append(times, time)
			}
		}
	}

	if len(times) == 0 {
		return 0, errors.New("no ping times found")
	}

	// Calculate average
	var sum float64
	for _, t := range times {
		sum += t
	}

	return sum / float64(len(times)), nil
}

