package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build platform-specific ping command
	var cmd *exec.Cmd
	countFlag := "-c"
	if runtime.GOOS == "windows" {
		countFlag = "-n"
	}

	// Use exec.Command with separate arguments to avoid shell injection
	cmd = exec.Command("ping", countFlag, strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outputStr)
	}

	// Look for the line containing RTT statistics
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Support different ping output formats
		if strings.Contains(line, "rtt min/avg/max") || 
		   strings.Contains(line, "round-trip min/avg/max") ||
		   strings.Contains(strings.ToLower(line), "minimum") && strings.Contains(strings.ToLower(line), "average") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract average latency using more flexible regex patterns
	// Try different patterns for different ping output formats

	// Pattern 1: Linux/Unix format with mdev: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re1 := regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re1.FindStringSubmatch(statsLine)

	// Pattern 2: Linux/Unix format without mdev: rtt min/avg/max = 12.345/23.456/34.567 ms
	if len(matches) < 2 {
		re2 := regexp.MustCompile(`rtt min/avg/max = [\d.]+/([\d.]+)/[\d.]+ ms`)
		matches = re2.FindStringSubmatch(statsLine)
	}

	// Pattern 3: macOS format: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	if len(matches) < 2 {
		re3 := regexp.MustCompile(`round-trip min/avg/max/stddev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
		matches = re3.FindStringSubmatch(statsLine)
	}

	// Pattern 4: Windows format: Minimum = 12ms, Maximum = 34ms, Average = 23ms
	if len(matches) < 2 {
		re4 := regexp.MustCompile(`Average = ([\d.]+)ms`)
		matches = re4.FindStringSubmatch(statsLine)
	}

	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

