		// Windows output format: "Average = Xms" or "平均 = Xms" (localized)
		avgRegex = regexp.MustCompile(`(?:Average|平均)\s*=\s*(\d+(?:\.\d+)?)ms`)
	case "darwin", "linux":
		// Unix-like: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Unix output format: "min/avg/max/stddev = X/Y/Z/W ms" or "rtt min/avg/max/mdev = X/Y/Z/W ms"
		avgRegex = regexp.MustCompile(`(?:min/avg/max/(?:stddev|mdev)\s*=\s*[\d.]+/([\d.]+)/|avg\s*=\s*([\d.]+))`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Parse the average latency from the output
	matches := avgRegex.FindStringSubmatch(outputStr)
	if matches == nil {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", outputStr)
	}

	// Extract the average value from the regex matches
	var avgStr string
	for i := 1; i < len(matches); i++ {
		if matches[i] != "" {
			avgStr = matches[i]
			break
		}
	}

	if avgStr == "" {
		return 0, fmt.Errorf("failed to extract average latency value")
	}

	// Convert to float64
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}

