		// or "rtt min/avg/max/mdev = XXX/XXX/XXX/XXX ms"
		avgPattern = regexp.MustCompile(`(?:min/avg/max/(?:stddev|mdev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms)|(?:avg\s*=\s*([\d.]+)\s*ms)`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Parse the average latency from the output
	matches := avgPattern.FindStringSubmatch(outputStr)
	if matches == nil {
		return 0, fmt.Errorf("could not parse average latency from ping output: %s", outputStr)
	}

	// Extract the average value from the matched groups
	var avgStr string
	for i := 1; i < len(matches); i++ {
		if matches[i] != "" {
			avgStr = matches[i]
			break
		}
	}

	if avgStr == "" {
		return 0, fmt.Errorf("could not extract average latency value")
	}

	// Convert to float64
	avgLatency, err := strconv.ParseFloat(strings.TrimSpace(avgStr), 64)
	if err != nil {
		return 0, fmt.Errorf("could not convert average latency to float: %v", err)
	}

	return avgLatency, nil
}

