// MeasureLatency pings a specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	// Build ping command based on operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	case "darwin", "linux":
		// macOS/Linux: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	// Parse the output to extract average latency
	avgLatency, err := parseAverageLatency(string(output), runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %v", err)
	}

	return avgLatency, nil
}

// parseAverageLatency extracts the average latency from ping command output
func parseAverageLatency(output, os string) (float64, error) {
	switch os {
	case "windows":
		// Windows output format: "Average = XXXms" or "Average = XXXXms"
		re := regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 2 {
			return 0, fmt.Errorf("could not find average latency in output")
		}
		return strconv.ParseFloat(matches[1], 64)

	case "darwin":
		// macOS output format: "round-trip min/avg/max/stddev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
		re := regexp.MustCompile(`round-trip min/avg/max/stddev = ([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+) ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 3 {
			return 0, fmt.Errorf("could not find average latency in output")
		}
		return strconv.ParseFloat(matches[2], 64)

	case "linux":
		// Linux output format: "rtt min/avg/max/mdev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
		re := regexp.MustCompile(`rtt min/avg/max/mdev = ([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+) ms`)
		matches := re.FindStringSubmatch(output)
		if len(matches) < 3 {
			return 0, fmt.Errorf("could not find average latency in output")
		}
		return strconv.ParseFloat(matches[2], 64)

	default:
