// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	var avgPattern *regexp.Regexp

	// Platform-specific ping command configuration
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
		// Windows output format: "Average = XXXms" or "Average = XXXXms"
		avgPattern = regexp.MustCompile(`Average\s*=\s*(\d+)ms`)
	case "darwin":
		// macOS: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// macOS output format: "round-trip min/avg/max/stddev = X.XXX/X.XXX/X.XXX/X.XXX ms"
		avgPattern = regexp.MustCompile(`min/avg/max/[^=]+=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	case "linux":
		// Linux: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Linux output format: "rtt min/avg/max/mdev = X.XXX/X.XXX/X.XXX/X.XXX ms"
		avgPattern = regexp.MustCompile(`rtt min/avg/max/mdev\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	// Parse the output to extract average latency
	outputStr := string(output)
	matches := avgPattern.FindStringSubmatch(outputStr)

	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse ping output: %s", outputStr)
	}

	// Convert the captured average latency to float64
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %v", err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	examples := []struct {
		host  string
		count int
	}{
		{"8.8.8.8", 4},
		{"google.com", 3},
		{"localhost", 2},
	}

	fmt.Println("Network Latency Measurement Tool")
	fmt.Println(strings.Repeat("=", 50))

	for _, example := range examples {
		fmt.Printf("\nPinging %s with %d attempts...\n", example.host, example.count)

		avgLatency, err := MeasureLatency(example.host, example.count)
		if err != nil {
			fmt.Printf("Error: %v\n", err)
			continue
		}

		fmt.Printf("Average latency: %.2f ms\n", avgLatency)
	}

	// Interactive example
	fmt.Println("\n" + strings.Repeat("=", 50))
	fmt.Println("\nCustom measurement:")

	customHost := "1.1.1.1"
	customCount := 5

	fmt.Printf("Pinging %s with %d attempts...\n", customHost, customCount)
	avgLatency, err := MeasureLatency(customHost, customCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	} else {
		fmt.Printf("Average latency: %.2f ms\n", avgLatency)
	}
}

