// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be greater than 0")
	}

	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}

	var cmd *exec.Cmd
	var avgRegex *regexp.Regexp

	// Platform-specific ping command construction
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
		// Windows output format: "Average = XXXms" or "Average = XXXms"
		avgRegex = regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)ms`)
	case "darwin", "linux":
		// Unix-like: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
		// Unix output format: "min/avg/max/stddev = X.XXX/Y.YYY/Z.ZZZ/W.WWW ms"
		avgRegex = regexp.MustCompile(`min/avg/max(?:/[a-z]+)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, output: %s", err, string(output))
	}

	outputStr := string(output)

	// Parse the average latency from the output
	matches := avgRegex.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		// Try alternative parsing methods
		avgLatency, parseErr := parseAlternative(outputStr, runtime.GOOS)
		if parseErr != nil {
			return 0, fmt.Errorf("failed to parse average latency from ping output: %s", outputStr)
		}
		return avgLatency, nil
	}

	// Convert the captured average latency to float64
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float64: %v", err)
	}

	return avgLatency, nil
}

// parseAlternative attempts alternative parsing methods for different output formats
func parseAlternative(output string, os string) (float64, error) {
	if os == "windows" {
		// Try parsing individual ping times and calculate average manually
		timeRegex := regexp.MustCompile(`time[=<](\d+)ms`)
		matches := timeRegex.FindAllStringSubmatch(output, -1)
		if len(matches) > 0 {
			var sum float64
			for _, match := range matches {
				if len(match) >= 2 {
					val, err := strconv.ParseFloat(match[1], 64)
					if err == nil {
						sum += val
					}
				}
			}
			if len(matches) > 0 {
				return sum / float64(len(matches)), nil
			}
		}
	} else {
		// For Unix-like systems, try alternative format
		lines := strings.Split(output, "\n")
		for _, line := range lines {
			if strings.Contains(line, "avg") || strings.Contains(line, "rtt") {
				// Try to extract numbers from the statistics line
				numRegex := regexp.MustCompile(`[\d.]+`)
				numbers := numRegex.FindAllString(line, -1)
				if len(numbers) >= 2 {
					// Usually the second number is the average
					avg, err := strconv.ParseFloat(numbers[1], 64)
					if err == nil {
						return avg, nil
					}
				}
			}
		}
	}
	return 0, fmt.Errorf("unable to parse ping output")
}

func main() {
